<template><div class="page-container"><el-card><template #header><span>往来流水</span></template><el-form :inline="true"><el-form-item label="交易类型"><el-select v-model="f.transaction_type" clearable><el-option v-for="t in ['收款','付款']" :key="t" :label="t" :value="t"/></el-select></el-form-item><el-form-item label="搜索"><el-input v-model="f.search" placeholder="流水号/对方名称" clearable style="width:200px"/></el-form-item><el-form-item><el-button type="primary" @click="search">查询</el-button><el-button @click="handleExport">导出</el-button></el-form-item></el-form><el-table :data="list" border stripe v-loading="loading"><el-table-column prop="flow_no" label="流水号" width="150"/><el-table-column prop="transaction_type" label="交易类型" width="80"/><el-table-column prop="counterparty_name" label="对方名称" width="150"/><el-table-column prop="amount" label="金额" width="120"><template #default="{ row }"><span :style="{color:row.amount>0?'red':'green'}">{{ row.amount }}</span></template></el-table-column><el-table-column prop="currency" label="币种" width="80"/><el-table-column prop="pay_method" label="付款方式" width="100"/><el-table-column prop="transaction_date" label="交易日期" width="120"/><el-table-column prop="remark" label="备注"/></el-table><el-pagination v-model:current-page="p.page" layout="total,prev,pager,next" :total="p.total" @current-change="load"/></el-card></div></template>
<script setup>import { ref, reactive, onMounted } from 'vue'; import { getTransactionFlows } from '@/api/finance'
const f = reactive({ transaction_type: '', search: '' }); const list = ref([]); const loading = ref(false); const p = reactive({ page: 1, total: 0 })
async function load() { loading.value = true; try { const data = await getTransactionFlows({ ...f, page: p.page }); list.value = data?.results || data || []; p.total = data?.count || 0 } catch { } finally { loading.value = false } }
function search() { p.page = 1; load() }
function handleExport() { /* export */ }
onMounted(load)
</script>
